/**
 * main.js
 *
 * Client-side bootstrap for the CV page.
 * Fetches the three HTML fragments generated by utils/build.js and injects them
 * into their respective placeholder elements in index.html.
 *
 * Fragment → placeholder mapping:
 *   public/header.html → #header-content  (name, photo, summary)
 *   public/left.html   → #left-content    (strengths, contact, skills)
 *   public/right.html  → #right-content   (experience)
 */

document.getElementById('year').textContent = new Date().getFullYear();

Promise.all([
    fetch('public/header.html').then(r => r.text()),
    fetch('public/left.html').then(r => r.text()),
    fetch('public/right.html').then(r => r.text()),
]).then(([header, left, right]) => {
    document.getElementById('header-content').innerHTML = header;
    document.getElementById('left-content').innerHTML   = left;
    document.getElementById('right-content').innerHTML  = right;
});
